const item = $input.item.json;

if (!item.eventName) throw new Error('eventName is required');
if (!item.photos || !Array.isArray(item.photos) || item.photos.length < 2) {
  throw new Error('photos array with at least 2 items is required');
}

var seen = {};
var photos = item.photos
  .map(function(p) { return { url: (p.url || p).trim(), label: p.label || '' }; })
  .filter(function(p) {
    if (!p.url.startsWith('https://') || seen[p.url]) return false;
    seen[p.url] = true;
    return true;
  })
  .slice(0, 10);

if (photos.length < 2) throw new Error('Need at least 2 valid unique HTTPS photo URLs');

var rawTags = item.hashtags || ['eventrecap', 'photodump', 'nightout', 'memories'];
var hashtagBlock = (Array.isArray(rawTags) ? rawTags : [rawTags])
  .join(' ').split(/[,\s]+/).filter(Boolean)
  .map(function(h) { return h.startsWith('#') ? h : '#' + h; }).join(' ');

var parts = [item.eventName + ' - swipe to relive the night ->\n'];
if (item.location && item.eventDate) parts.push(item.location + '  -  ' + item.eventDate + '\n');
else if (item.location)  parts.push(item.location + '\n');
else if (item.eventDate) parts.push(item.eventDate + '\n');
if (item.attendees) parts.push(Number(item.attendees).toLocaleString() + ' people in the building\n');
if (item.caption)   parts.push(item.caption.trim() + '\n');
if (item.highlights && item.highlights.length) {
  var hl = Array.isArray(item.highlights) ? item.highlights : [item.highlights];
  parts.push('Highlights:\n' + hl.slice(0,5).map(function(h,i){return (i+1)+'. '+h;}).join('\n') + '\n');
}
if (item.nextEventDate) parts.push('Next one: ' + item.nextEventDate + ' - stay locked.\n');
parts.push(hashtagBlock);

var fullCaption = parts.join('\n').trim();
if (fullCaption.length > 2200) fullCaption = fullCaption.substring(0, 2196) + '...';

return photos.map(function(photo, idx) {
  return {
    json: {
      photoUrl:    photo.url,
      photoLabel:  photo.label,
      slideIndex:  idx + 1,
      slideCount:  photos.length,
      fullCaption: fullCaption,
      eventName:   item.eventName,
      igUserId:    $env.IG_USER_ID,
      accessToken: $env.IG_ACCESS_TOKEN
    }
  };
});

const item = $input.item.json;

const publicUrl = item.public_url || item.url || item.file_url || item.cdn_url || '';
if (!publicUrl) {
  throw new Error('Upload to URL returned no public URL for slide ' + item.slideIndex + '. Keys: ' + JSON.stringify(Object.keys(item)));
}

const igUserId    = $env.IG_USER_ID;
const accessToken = $env.IG_ACCESS_TOKEN;

const res = await fetch('https://graph.facebook.com/v19.0/' + igUserId + '/media', {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    image_url:        publicUrl,
    media_type:       'IMAGE',
    is_carousel_item: true,
    access_token:     accessToken
  })
});

const data = await res.json();
if (data.error) {
  throw new Error('IG child container error (slide ' + item.slideIndex + '): ' + data.error.message);
}

return {
  ...item,
  childContainerId: data.id,
  cdnUrl: publicUrl
};

const allItems = $input.all();

var sorted = allItems
  .map(function(i) { return i.json; })
  .filter(function(d) { return d.childContainerId; })
  .sort(function(a, b) { return a.slideIndex - b.slideIndex; });

if (sorted.length < 2) {
  throw new Error('Need at least 2 child containers. Got: ' + sorted.length);
}

var first = sorted[0];

return {
  childrenParam: sorted.map(function(d) { return d.childContainerId; }).join(','),
  slideLog:      sorted.map(function(d) { return { slide: d.slideIndex, id: d.childContainerId, url: d.cdnUrl }; }),
  slideCount:    sorted.length,
  fullCaption:   first.fullCaption,
  eventName:     first.eventName,
  igUserId:      first.igUserId,
  accessToken:   first.accessToken
};

